import { Component, OnInit, ViewChild } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { IonInput, ModalController, NavController, ToastController } from '@ionic/angular';
import { NgxMaskModule,MaskPipe } from 'ngx-mask';
import {UserService} from './../services/user.service';
import { LoadingController } from '@ionic/angular';

@Component({
  selector: 'app-login',
  templateUrl: './login.page.html',
  styleUrls: ['./login.page.scss'],
})
export class LoginPage implements OnInit {

  ionicForm: FormGroup;
  @ViewChild('phone') phone : IonInput ;
  @ViewChild('password') password : IonInput;
  phone_model: string = "";

  phone_error:string = "";
  pwd_error:string = "";
  error_response:string = "";

  constructor(private loadingCtrl: LoadingController, private userService:UserService, private router: Router, private nav:NavController, private modalController: ModalController, private toastController: ToastController, private maskPipe:MaskPipe, public formBuilder: FormBuilder) { }

  ngOnInit() {
    this.buildForm();
  }


  buildForm() {
    this.ionicForm = this.formBuilder.group({
      phone: ['', [Validators.required]],
      password: ['', [Validators.required]],
    })    
  }


  updateWithMask(event) {
    this.ionicForm.controls.phone.setValue(this.maskPipe.transform(event.currentTarget.value, '(000) 000-00-00'));
  }


  async submitForm() {
    this.phone_error = "";
    this.pwd_error = "";
    this.error_response ="";
    console.log(this.ionicForm.value);
    let phone = this.ionicForm.value.phone;
    let password = this.ionicForm.value.password;

    if (phone=='') {
      this.phone_error = "Телефон не может быть пустым!";
    }
    if (password=='') {
      this.pwd_error = "Пароль не может быть пустым!";
    }

    if (phone!='' && password !='') {

      const loading = await this.loadingCtrl.create({
        message: 'Подождите...',
      });
      loading.present();

      this.userService.login(phone,password).then(response=>{

        loading.dismiss();        
        if (response.error) {
          this.error_response = response.message;
        } else {
          this.nav.navigateRoot(['orders']);
        }


      }).catch(err=>{
        console.log("login.ts this.userService.login error:");
        console.log(err);
        loading.dismiss();
      });
    }

  }

  pwdSetFocus() { 
    this.password.setFocus();
  }
  
}
